import React, { useState, useEffect, useRef } from 'react';
import { Link } from 'react-router-dom';
import { getRoomTypes } from '../api/rooms';

export default function HomePage() {
  const [roomTypes, setRoomTypes] = useState([]);
  const [typesLoading, setTypesLoading] = useState(true);
  const [roomTypeImages, setRoomTypeImages] = useState({});
  const [activeIndex, setActiveIndex] = useState(null);
  const heroRef = useRef(null);
  const [mousePosition, setMousePosition] = useState({ x: 0, y: 0 });

  // Fetch room types on component mount
  useEffect(() => {
    const fetchRoomTypes = async () => {
      try {
        const { data } = await getRoomTypes();
        const types = data.results || data;
        setRoomTypes(types);

        // Generate aesthetic images for each room type
        const images = {};
        types.forEach(type => {
          const name = type.name.toLowerCase();
          if (name === 'standard') {
            images[type.id] = { 
              bg: 'linear-gradient(135deg, #667eea 0%, #764ba2 100%)', 
              accent: '#667eea', 
              icon: '🛏️',
              gradient: 'linear-gradient(135deg, rgba(102,126,234,0.1) 0%, rgba(118,75,162,0.1) 100%)'
            };
          } else if (name === 'deluxe') {
            images[type.id] = { 
              bg: 'linear-gradient(135deg, #f093fb 0%, #f5576c 100%)', 
              accent: '#f5576c', 
              icon: '✨',
              gradient: 'linear-gradient(135deg, rgba(240,147,251,0.1) 0%, rgba(245,87,108,0.1) 100%)'
            };
          } else if (name === 'suite') {
            images[type.id] = { 
              bg: 'linear-gradient(135deg, #4facfe 0%, #00f2fe 100%)', 
              accent: '#4facfe', 
              icon: '👑',
              gradient: 'linear-gradient(135deg, rgba(79,172,254,0.1) 0%, rgba(0,242,254,0.1) 100%)'
            };
          } else {
            images[type.id] = { 
              bg: 'linear-gradient(135deg, #43e97b 0%, #38f9d7 100%)', 
              accent: '#43e97b', 
              icon: '🏨',
              gradient: 'linear-gradient(135deg, rgba(67,233,123,0.1) 0%, rgba(56,249,215,0.1) 100%)'
            };
          }
        });
        setRoomTypeImages(images);
      } catch (error) {
        console.error('Error fetching room types:', error);
      } finally {
        setTypesLoading(false);
      }
    };
    fetchRoomTypes();
  }, []);

  // Mouse move effect for hero section
  useEffect(() => {
    const handleMouseMove = (e) => {
      setMousePosition({
        x: (e.clientX / window.innerWidth - 0.5) * 20,
        y: (e.clientY / window.innerHeight - 0.5) * 20
      });
    };
    window.addEventListener('mousemove', handleMouseMove);
    return () => window.removeEventListener('mousemove', handleMouseMove);
  }, []);

  // Format price
  const formatPrice = (price) => `₱${Number(price).toLocaleString()}/night`;

  // Get room description
  const getRoomDescription = (typeName) => {
    const name = typeName.toLowerCase();
    if (name === 'standard') {
      return 'Elegantly designed spaces that blend comfort with contemporary sophistication.';
    } else if (name === 'deluxe') {
      return 'Luxuriously appointed rooms featuring premium amenities and breathtaking vistas.';
    } else if (name === 'suite') {
      return 'The epitome of luxury with separate living areas and exclusive butler service.';
    }
    return `Experience unparalleled luxury in our ${typeName} rooms with bespoke amenities.`;
  };

  // Scroll to section
  const scrollToSection = (sectionId) => {
    const section = document.getElementById(sectionId);
    if (section) {
      section.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  };

  return (
    <div style={{ overflowX: 'hidden' }}>
      {/* Hero Section - Premium Glassmorphism */}
      <section
        ref={heroRef}
        style={{
          minHeight: '100vh',
          position: 'relative',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          background: 'radial-gradient(circle at 20% 50%, #0a0f2a 0%, #060914 100%)',
          overflow: 'hidden',
        }}
      >
        {/* Animated gradient orbs */}
        <div style={{
          position: 'absolute',
          width: '50vw',
          height: '50vw',
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(102,126,234,0.3) 0%, transparent 70%)',
          top: '20%',
          left: '-10%',
          animation: 'floatOrb 8s ease-in-out infinite',
          filter: 'blur(80px)'
        }} />
        <div style={{
          position: 'absolute',
          width: '40vw',
          height: '40vw',
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(245,87,108,0.3) 0%, transparent 70%)',
          bottom: '10%',
          right: '-5%',
          animation: 'floatOrb 10s ease-in-out infinite reverse',
          filter: 'blur(80px)'
        }} />
        <div style={{
          position: 'absolute',
          width: '30vw',
          height: '30vw',
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(79,172,254,0.2) 0%, transparent 70%)',
          top: '50%',
          right: '20%',
          animation: 'floatOrb 12s ease-in-out infinite',
          filter: 'blur(60px)'
        }} />

        {/* Mouse-following glow */}
        <div style={{
          position: 'absolute',
          width: '300px',
          height: '300px',
          borderRadius: '50%',
          background: 'radial-gradient(circle, rgba(255,255,255,0.1) 0%, transparent 70%)',
          transform: `translate(${mousePosition.x}px, ${mousePosition.y}px)`,
          transition: 'transform 0.1s ease-out',
          pointerEvents: 'none',
          zIndex: 1
        }} />

        <div style={{
          position: 'relative',
          zIndex: 2,
          textAlign: 'center',
          padding: '0 24px',
          maxWidth: '900px'
        }}>
          {/* Premium badge */}
          <div style={{
            display: 'inline-block',
            padding: '8px 24px',
            background: 'rgba(255,255,255,0.05)',
            backdropFilter: 'blur(10px)',
            borderRadius: '100px',
            border: '1px solid rgba(255,255,255,0.1)',
            marginBottom: '32px',
            animation: 'fadeInDown 0.8s ease'
          }}>
            <span style={{
              fontSize: '0.7rem',
              letterSpacing: '0.2em',
              color: '#c9a84c',
              textTransform: 'uppercase',
              fontWeight: 500
            }}>
              ★ Five-Star Hospitality ★
            </span>
          </div>

          <h1 style={{
            fontSize: 'clamp(3rem, 8vw, 6rem)',
            fontWeight: 600,
            marginBottom: '24px',
            background: 'linear-gradient(135deg, #ffffff 0%, #e0e0e0 50%, #ffffff 100%)',
            backgroundClip: 'text',
            WebkitBackgroundClip: 'text',
            color: 'transparent',
            letterSpacing: '-0.02em',
            animation: 'fadeInUp 0.8s ease'
          }}>
            Where Luxury
            <br />
            <span style={{
              background: 'linear-gradient(135deg, #c9a84c, #ffd700, #c9a84c)',
              backgroundClip: 'text',
              WebkitBackgroundClip: 'text',
              color: 'transparent',
              fontStyle: 'italic'
            }}>
              Meets Comfort
            </span>
          </h1>

          <p style={{
            fontSize: 'clamp(1rem, 1.5vw, 1.2rem)',
